source:
State -> {
  -> Idle:
  -> Selecting:
  -> Paying:
  -> Dispensing:
}

Insert -> { u8:coin }
Select -> { u8:slot }
Cancel -> {}

Machine -> {
  State:current >>- Insert -> Idle:
  Insert -< e {
    current -<< Selecting:
  }
  Cancel -< e {
    current -<< Idle:
  }
  pressSelect -> {
    u8:slot
    >- Select{slot -> slot}
  }
}
